const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// --- Credential Management ---
// It is crucial to set these as environment variables in your Cloud Function deployment.
// For Google Cloud Functions, you can set them during deployment using:
// gcloud functions deploy YOUR_FUNCTION_NAME --runtime nodejs18 --trigger-http \
//   --set-env-vars SENDGRID_API_KEY=YOUR_SENDGRID_API_KEY,TWILIO_ACCOUNT_SID=YOUR_TWILIO_ACCOUNT_SID,TWILIO_AUTH_TOKEN=YOUR_TWILIO_AUTH_TOKEN
// Or use the Cloud Console UI.

const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID;
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN;

// --- Initialize SendGrid ---
if (!SENDGRID_API_KEY) {
  console.error('SENDGRID_API_KEY environment variable is not set.');
  // In a real deployment, you might want to throw an error or handle this more gracefully
  // before the function starts receiving requests.
} else {
  sgMail.setApiKey(SENDGRID_API_KEY);
}

// --- Initialize Twilio ---
let twilioClient;
if (!TWILIO_ACCOUNT_SID || !TWILIO_AUTH_TOKEN) {
  console.error('TWILIO_ACCOUNT_SID or TWILIO_AUTH_TOKEN environment variables are not set.');
} else {
  twilioClient = new twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);
}

/**
 * Node.js Cloud Function that sends emails via SendGrid and SMS via Twilio.
 *
 * This function expects an HTTP POST request with a JSON body.
 * The JSON body must contain a 'type' field ("email" or "sms")
 * and an object corresponding to the message type ('email' or 'sms').
 *
 * Example Email Request Body:
 * {
 *   "type": "email",
 *   "email": {
 *     "to": "recipient@example.com",
 *     "from": "sender@example.com", // Must be a verified SendGrid sender
 *     "subject": "Hello from Cloud Function!",
 *     "text": "This is a test email sent via SendGrid.",
 *     "html": "<strong>This is a test email sent via SendGrid.</strong>"
 *   }
 * }
 *
 * Example SMS Request Body:
 * {
 *   "type": "sms",
 *   "sms": {
 *     "to": "+1234567890",      // Recipient's phone number in E.164 format
 *     "from": "+11234567890",    // Your Twilio provisioned phone number in E.164 format
 *     "body": "Hello from Cloud Function! This is a test SMS via Twilio."
 *   }
 * }
 *
 * @param {object} req The request object.
 * @param {object} res The response object.
 */
exports.sendCommunication = async (req, res) => {
  // Ensure the request body is present
  if (!req.body) {
    console.error('No request body provided.');
    return res.status(400).send('No request body provided.');
  }

  const { type, email, sms } = req.body;

  // Validate the 'type' field
  if (!type) {
    console.error('Missing "type" in request body.');
    return res.status(400).send('Missing "type" in request body (must be "email" or "sms").');
  }

  try {
    if (type === 'email') {
      // --- SendGrid Email Logic ---
      if (!SENDGRID_API_KEY) {
        console.error('SendGrid API Key is not configured.');
        return res.status(500).send('SendGrid service is not configured.');
      }
      if (!email) {
        console.error('Missing "email" object for email type.');
        return res.status(400).send('Missing "email" object for email type.');
      }

      const { to, from, subject, text, html } = email;

      // Validate required email fields
      if (!to || !from || !subject || (!text && !html)) {
        console.error('Missing required email fields:', { to, from, subject, text, html });
        return res.status(400).send('Missing required email fields: to, from, subject, and either text or html.');
      }

      const msg = { to, from, subject, text, html };
      await sgMail.send(msg);
      console.log('Email sent successfully to:', to);
      res.status(200).send('Email sent successfully!');

    } else if (type === 'sms') {
      // --- Twilio SMS Logic ---
      if (!twilioClient) {
        console.error('Twilio client is not configured.');
        return res.status(500).send('Twilio service is not configured.');
      }
      if (!sms) {
        console.error('Missing "sms" object for sms type.');
        return res.status(400).send('Missing "sms" object for sms type.');
      }

      const { to, from, body } = sms;

      // Validate required SMS fields
      if (!to || !from || !body) {
        console.error('Missing required SMS fields:', { to, from, body });
        return res.status(400).send('Missing required SMS fields: to, from, body.');
      }

      await twilioClient.messages.create({ to, from, body });
      console.log('SMS sent successfully to:', to);
      res.status(200).send('SMS sent successfully!');

    } else {
      // Handle unknown message type
      console.error('Invalid "type" specified:', type);
      return res.status(400).send('Invalid "type" specified. Must be "email" or "sms".');
    }
  } catch (error) {
    console.error('Error sending communication:', error);

    // Provide more specific error details for SendGrid if available
    if (error.response && error.response.body) {
      console.error('SendGrid Error Details:', error.response.body);
      return res.status(500).send(`Failed to send communication: ${error.message}. Details: ${JSON.stringify(error.response.body)}`);
    }

    // Generic error response
    return res.status(500).send(`Failed to send communication: ${error.message}`);
  }
};

